<template>
  <v-container fluid class="pa-6 pt-4 fill-height closed-circuit-television white" ref="cctvReference">
    <v-row no-gutters class="fill-height">
      <v-sheet width="100%" height="33" class="d-flex align-center">
        <h3 class="font-weight-bold">{{ $t('safetyMonitoring') }}</h3>
        <v-spacer />
        <!-- <v-tooltip bottom>
          <template #activator="{ on, attrs }">
            <v-sheet v-bind="attrs" v-on="on" width="24" height="24" class="mr-4">
              <v-checkbox
                v-model="isHideHeader"
                inset
                height="24"
                width="24"
                class="pa-0"
                :ripple="false"
              />
            </v-sheet>
          </template>
          <span>{{ `카메라 제목 숨기기` }}</span>
        </v-tooltip> -->
        <v-tooltip bottom>
          <template #activator="{ on, attrs }">
            <v-btn
              icon
              :ripple="false"
              v-bind="attrs"
              v-on="on"
              @click.prevent="isFullScreen ? closeFullScreen() : onFullScreen()"
            >
              <v-icon>{{ `${isFullScreen ? 'mdi-fullscreen-exit' : 'mdi-fullscreen'}` }}</v-icon>
            </v-btn>
          </template>
          <span>{{ `${$t('fullscreen')} ${isFullScreen ? $t('btnClose') : ''}` }}</span>
        </v-tooltip>
      </v-sheet>
      <v-sheet width="100%" height="calc(100% - 32px)" class="pt-2 overflow-hidden">
        <v-row no-gutters class="pa-0 fill-height">
          <v-card width="150" color="login_bg" class="pa-2 fill-height red closed-circuit-television-group">
            <v-list nav dense class="login_bg">
              <v-list-item-group v-model="selected" color="primary" class="login_bg">
                <template v-for="(item, i) in groupList">
                  <v-list-item :key="i" :input-value="item.id" :disabled="item.id == selected" :value="item.id" class="login_bg" @click="handleCCTV(item.id)">
                    <v-list-item-content>
                      <v-list-item-title v-text="item.Profile_name" class="text-subtitle-2" />
                    </v-list-item-content>
                    <v-list-item-action class="align-center justify-end">
                      <template v-if="!layoutLoading && item.isAlert">
                        <v-icon size="10" color="error" class="closed-circuit-television-group-alert">mdi-circle</v-icon>
                      </template>
                    </v-list-item-action>
                  </v-list-item>
                </template>
              </v-list-item-group>
            </v-list>
          </v-card>
          <v-col class="fill-height overflow-x-hidden overflow-y-auto smart-widget-grid-area">
            <smart-widget-grid
              :layout="cctvList"
              :colNum="48"
              :rowHeight="48"
              :headerHeight="40"
              fixedHeight
              :resizable="false"
              :draggable="false"
              shadow="never"
              class="fill-height"
            >
              <template v-for="(cctv, cctv_index) in cctvList">
                <smart-widget :key="cctv_index" :slot="cctv.i" :simple="isHideHeader">
                  <template #title>
                    <span class="font-weight-bold text-subtitle-1">{{ `${cctv.title}` }}</span>
                    <!-- <span class="ml-2 font-weight-medium text-subtitle-1 grey--text">{{ `(${cctv.cctv_id})` }}</span> -->
                  </template>
                  <template #toolbar>
                    <v-sheet height="100%" class="pr-2">
                      <v-btn icon :ripple="false" @click.prevent="onVideoFullScreen(cctv_index)">
                        <v-icon>mdi-fullscreen</v-icon>
                      </v-btn>
                    </v-sheet>
                  </template>
                  <template #default>
                    <v-sheet width="100%" height="100%" color="#1E1E1E" class="d-flex align-center justify-center" :ref="`videoIframe${cctv_index}`">
                      <template v-if="loading[cctv_index]">
                        <v-progress-circular indeterminate color="white" />
                      </template>
                      <iframe
                        v-show="!loading[cctv_index]"
                        width="100%"
                        height="100%"
                        :src="`${cctv.cctv_play_url}?controls=0`"
                        frameborder="0"
                        :allowfullscreen="true"
                        allow="fullscreen; encrypted-media; autoplay;"
                        :class="['iframe-class', cctv.class]"
                        @load="onVideoLoad(cctv_index)"
                      />
                      <template v-if="isVideoFullScreen">
                        <h1 class="ma-3 full-screen-title font-weight-bold warning--text">{{ `${cctv.cctv_id}` }}</h1>
                        <v-btn icon :ripple="false" class="ma-3 full-screen-close-button" @click.prevent="closeFullScreen">
                          <v-icon size="42" color="white">mdi-close</v-icon>
                        </v-btn>
                      </template>
                      <template v-else>
                        <h5 class="ma-3 full-screen-title font-weight-bold warning--text">{{ `${cctv.cctv_id}` }}</h5>
                      </template>
                    </v-sheet>
                  </template>
                </smart-widget>
              </template>
            </smart-widget-grid>
            <template v-if="cctvList.length == 0">
              <span class="closed-circuit-television-empty-text">
                {{ layoutLoading ? $t('msgLoadingCamera') : $t('msgNoConnectedCameras') }}
              </span>
            </template>
          </v-col>
          <v-sheet width="320" height="100%" color="card_bg" class="pa-3 d-flex flex-column">
            <v-sheet class="d-flex align-start flex-wrap" color="transparent">
              <template v-for="(issueItem, issueIndex) in issueAlertCountList">
                <v-col cols="6" class="pa-0">
                  <v-card
                    height="100"
                    rounded="lg"
                    color="condition_bg"
                    class="pa-2 mb-3 d-flex flex-column justify-space-around"
                    :class="[ issueIndex % 2 ? 'alert-card-left' : 'alert-card-right' ]"
                  >
                    <v-card-title class="pa-0 px-2 d-flex align-center justify-space-around">
                      <svg-icon :icon-class="`safety-event-${issueItem.icon}`" />
                      <span class="font-weight-bold text-h4 secondary--text">{{ issueItem.count }}</span>
                    </v-card-title>
                    <v-card-text class="pa-0 d-flex align-center justify-center">
                      <span class="font-weight-bold secondary--text">{{ issueItem.text }}</span>
                    </v-card-text>
                  </v-card>
                </v-col>
              </template>
            </v-sheet>
            <v-col class="pa-0 closed-circuit-television-alert-history overflow-y-auto">
              <v-list class="pa-0 transparent">
                <template v-for="(issueItem, index) in issueAlertList">
                  <v-list-item :key="issueItem.id" class="white pl-2" :class="[{ 'closed-circuit-television-alert-history-not-read' : !issueItem.isread }]"  @click="onIssueHistory(issueItem)">
                    <v-list-item-avatar class="d-flex align-center justify-center">
                      <svg-icon :icon-class="`safety-event-${issueAlertCountListRef.find(el => el.id == issueItem.event_type).icon}`" />
                    </v-list-item-avatar>
                    <v-list-item-content class="align-self-center text-right secondary--text">
                      <v-list-item-title class="d-flex align-center justify-end font-weight-bold">
                        <span>{{ `${issueItem.cctv_id}` }}</span>
                        <v-divider vertical class="mx-2 my-1" />
                        <span>{{ issueItem.event_time }}</span>
                      </v-list-item-title>
                      <span class="font-weight-medium">{{ issueItem.event_desc }}</span>
                    </v-list-item-content>
                  </v-list-item>
                </template>
              </v-list>
            </v-col>
          </v-sheet>
        </v-row>
      </v-sheet>
    </v-row>
    <v-dialog v-model="issueDialog" persistent width="min-content" min-width="50vw">
      <v-card class="pa-4" height="80vh">
        <v-card-title class="pa-0 pb-4 text-subtitle-1 font-weight-bold primary--text">
          <span class="text-body-1 font-weight-bold">{{ selectedIssue.event_desc }}</span>
          <v-spacer />
          <span class="text-body-1 font-weight-bold grey--text">{{ selectedIssue.cctv_id }}</span>
          <v-divider vertical class="mx-2 grey--text" />
          <span class="text-body-1 font-weight-bold grey--text">{{ selectedIssue.event_time }}</span>
        </v-card-title>
        <v-sheet width="100%" height="calc(100% - 51px - 44px)">
          <v-card-text class="pa-0 d-flex align-center justify-center fill-height">
            <template v-if="selectedIssue">
              <template v-if="selectedIssue.event_type == 'E003'">
                <video controls height="100%" ref="videoPlayer" :style="`aspect-ratio: ${eventFile.ratio};`">
                  <source :src="eventFile.url" type="video/mp4" />
                </video>
              </template>
              <template v-else>
                <v-img height="100%" :style="`aspect-ratio: ${eventFile.ratio};`" :src="eventFile.url" />
              </template>
            </template>
          </v-card-text>
        </v-sheet>
        <v-card-actions class="pr-0 pb-0">
          <v-spacer />
          <v-btn small text outlined height="35" width="70" color="primary" @click="handleIssueDialog(false)">
            {{ $t('btnClose') }}
          </v-btn>
        </v-card-actions>
      </v-card>
    </v-dialog>
  </v-container>
</template>

<script>
import { getUserCd } from '@/utils/token'
import { getGroupList, getMonitoringList, setVideoStart, getVideo } from '@/api/realTimeVideoSafetyManagement/safetyMonitoring.js'
import { getEventGroupHistoryList, setEventReadAlert, getEventFiles, getCctvServerInfo } from '@/api/realTimeVideoSafetyManagement/safetyMonitoringHistory.js'

import baseview from '@/views/base/baseview.vue'
export default {
  mixins: [baseview],
  name: 'SafetyMonitoring',
  components: {
  },
  computed: {
    issueAlertCountList() {
      return this.issueAlertCountListRef.map(el => {
        const count = this.issueAlertList.filter(item => item.event_type === el.id).length
        return {
          ...el,
          count
        }
      })
    },
    groupList() {
      return this.groupListRef.map(el => {
        return {
          ...el,
          isAlert: this.groupAlert.find(fel => fel.profile_id == el.id)?.isAlert || false
        }
      })
    }
  },
  data() {
    return {
      isHideHeader: false,
      selected: 0,
      groupListRef: [],
      groupAlert: [],
      cctvList: [],
      issueIcon: 'mdi-alert',
      issueAlertCountListRef: [
        { id: 'E001', text: '안전모 미착용', color: 'yellow', icon: 'e001' },
        { id: 'E002', text: '위험구역 출입', color: 'yellow', icon: 'e002' },
        { id: 'E003', text: '작업자 쓰러짐', color: 'red', icon: 'e003' },
        { id: 'E004', text: '지게차 접근 감지', color: 'red', icon: 'e004' },
      ],
      issueAlertList: [],
      layoutLoading: true,
      loading: [],
      intervalAlertList: null,
      loadingDelay: 1000,
      isFullScreen: false,
      isVideoFullScreen: false,
      issueDialog: false,
      selectedIssue: {},
      isActive: true,
      eventFile: {
        ratio: 16/9,
        url: null
      }
    }
  },
  methods: {
    handleEventGroupHistory() {
      const param = {
        profile_id: this.selected,
        userCd: getUserCd()
      }
      getEventGroupHistoryList(param)
        .then(res => {
          this.groupAlert = res.group
          this.issueAlertList = res.list.map(el => {
            // const alert = this.issueAlertCountListRef.find(fel => fel.id == el.event_type)
            return {
              ...el
            }
          })
          setTimeout(() => {
            if(!this.layoutLoading && this.cctvList.length !== 0 && this.isActive) {
              this.handleEventGroupHistory()
            }
          }, 1000)
        })
    },
    getIssuePreview(param) {
      if(typeof param == 'number') {
        const find = this.issueAlertCountList.find(el => el.id == param)
        return find?.preview || null
      } else {
        return null
      }
    },
    handleKeydown(event) {
      if (this.isVideoFullScreen && event.key === 'Escape') {
        this.closeFullScreen()
      }
    },
    handleRatioClass(ratio) {
      let [x, y] = ratio ? ratio.split(':').map(Number) : [4, 3]
      return `ratio-${x}-${y}`
    },
    handleCreated() {
      getGroupList()
        .then(res => {
          this.groupListRef = res.list.map(el => ({
            id: el.Profile_id,
            Profile_name: el.Profile_name
          }))
          if(this.groupList.length !== 0) {
            this.selected = this.groupList[0].id
            this.handleCCTV(this.selected)
          }
        })
        .catch(() => {
          // console.error('서버의 상태가 원활하지않습니다.')
          return
        })
    },
    handleCCTV(param) {
      this.openLoading()
      this.cctvList = []
      this.issueAlertList = []
      this.layoutLoading = true
      getMonitoringList(param)
        .then(async res => {
          this.loading = Array(res.list.length).fill(true)
          this.cctvList = await res.list.map(el => {
            return {
              ...el,
              class: this.handleRatioClass(el.ratio)
            }
          })
          // this.intervalAlertList = setInterval(this.handleEventGroupHistory, 1000)
        })
        .finally(() => {
          this.endLoading()
          this.layoutLoading = false
          if(this.cctvList.length !== 0) {
            this.handleEventGroupHistory()
          }
        })
    },
    onVideoLoad(index) {
      setTimeout(() => {
        this.$set(this.loading, index, false)
      }, this.loadingDelay)
    },
    handleIssueDialog(isOpen) {
      this.eventFile.url = null
      this.issueDialog = isOpen || false
      if(isOpen) {

      } else {

      }
    },
    onIssueHistory(param) {
      this.selectedIssue = param
      param.isread = true
      this.handleIssueDialog(true)
      const fileParam = {
        cctv_id: param.cctv_id,
        file_path: param.file_path
      }
      if (param.event_type != 'E003') {
        getEventFiles(fileParam)
        .then(res => {
          if(res.success) {
            let [x, y] = res.ratio ? res.ratio.split(':').map(Number) : [4, 3]
            this.eventFile.ratio = x/y
            const byteCharacters = atob(res.img_decode_data)
            const byteNumbers = new Array(byteCharacters.length).fill().map((_, i) => byteCharacters.charCodeAt(i))
            const byteArray = new Uint8Array(byteNumbers)
            const blobType = param.event_type == 'E003' ? 'video/mp4' : 'image/jpeg'
            const blob = new Blob([byteArray], { type: blobType })
            this.eventFile.url = URL.createObjectURL(blob)
          }
        })
      } else {
        // Flask 서버에 파일 경로 전달
        let param1 = param.cctv_id
        getCctvServerInfo(param1).then(async res=> {
          // console.log(res)
          if(res.cctv_id === param.cctv_id) {
            this.eventFile.url = `http://${res.server_host}:${res.api_port}/cctv/process/video?path=${encodeURIComponent(param.file_path)}`;
            this.$nextTick(() => {
              this.$refs.videoPlayer.load(); // 비디오 다시 로드
            });
          }
        })
      }
      
      const readParam = {
        event_time: param.event_time,
        cctv_id: param.cctv_id
      }
      setEventReadAlert([readParam])
        then(res => {
          
        })
    },
    async onFullScreen(container) {
      if(!container) {
        container = this.$refs.cctvReference
        this.isFullScreen = true
      }
      if (container.requestFullscreen) {
        container.requestFullscreen()
      } else if (container.mozRequestFullScreen) {
        container.mozRequestFullScreen()
      } else if (container.webkitRequestFullscreen) {
        container.webkitRequestFullscreen()
      } else if (container.msRequestFullscreen) {
        container.msRequestFullscreen()
      }
    },
    async onVideoFullScreen(index) {
      const container = this.$refs['videoIframe' + index][0]?.$el
      this.onFullScreen(container)
      this.$nextTick(() => {
        window.addEventListener('keydown', this.handleKeydown)
      })
      this.isVideoFullScreen = true
    },
    closeFullScreen() {
      if (document.exitFullscreen) {
        document.exitFullscreen()
      } else if (document.mozCancelFullScreen) {
        document.mozCancelFullScreen()
      } else if (document.webkitExitFullscreen) {
        document.webkitExitFullscreen()
      } else if (document.msExitFullscreen) {
        document.msExitFullscreen()
      }
      this.isVideoFullScreen = false
      this.isFullScreen = false
    },
  },
  created() {
  },
  activated() {
    document.addEventListener('fullscreenchange', () => {
      if (!document.fullscreenElement) {
        this.isVideoFullScreen = false
        this.isFullScreen = false
      }
    })
    this.isActive = true
    this.handleCreated()
  },
  destroy() {
  },
  beforeRouteLeave(to, from, next) {
    window.removeEventListener('keydown', this.handleKeydown)
    this.isActive = false
    // clearInterval(this.handleEventGroupHistory)
    next()
  }
}
</script>

<style lang="scss">
.closed-circuit-television {
  $secondary: #3F51B5;
  $secondary-opacity: #3f51b544;
  .text-h4 {
    font-size: 1.9rem !important;
  }
  > div {
    position: relative;
    .v-list {
      height: 100%;
      overflow-y: auto;
    }
    .v-list-item--dense, .v-list--dense .v-list-item {
      min-height: 36px !important;
      padding: 0 8px !important;
      margin-bottom: 8px !important;
    }
    .alert-card {
      &-right {
        margin-right: 6px;
      }
      &-left {
        margin-left: 6px;
      }
    }
    .vue-grid-layout {
      height: 100% !important;
      .widget {
        &-header {
          display: flex;
          align-items: center;
          padding-left: 16px;
        }
      }
      .widget-body,
      .widget-body-simple {
        overflow: hidden;
        .widget-body__content {
          padding: 0 !important;
          .iframe-class {
            pointer-events: none;
            width: auto;
            height: 100%;
            border: none;
            object-fit: cover;
          }
        }
        .ratio-16-9 {
          aspect-ratio: 16 / 9;
        }
        .ratio-4-3 {
          aspect-ratio: 4 / 3;
        }
        .ratio-3-2 {
          aspect-ratio: 3 / 2;
        }
      }
    }
  }
  &-group {
    overflow: visible;
    &-alert {
      position: relative;
      animation: blink 1.75s infinite;
      &::after {
        content: '';
        position: absolute;
        top: 0;
        left: 0;
        right: 0;
        bottom: 0;
        width: 100% !important;
        height: 100% !important;
        border-radius: 50%;
        opacity: 1 !important;
        background: rgba(255, 0, 0, 1) !important;
        filter: blur(1px);
        z-index: 1;
        animation: pulse 1.75s infinite;
      }
    }
  }
  &-alert-history {
    .v-divider {
      &--vertical {
        border-width: 1px !important;
        border-color: $secondary-opacity;
      }
    }
    .v-list {
      &-item {
        border: 1px solid $secondary-opacity !important;
        border-radius: 5px;
        margin-bottom: 8px;
        &.closed-circuit-television-alert-history-not-read {
          position: relative;
          &::after {
            content: '';
            left: 0;
            top: 0;
            position: absolute;
            z-index: 1;
            border: 2px solid rgba(255, 0, 0, 0.5) !important;
            border-radius: 5px;
            width: 100%;
            height: 100%;
            animation: blink 2s infinite;
          }
        }
        &__avatar {
          margin-right: 0px !important;
        }
      }
    }
  }
  &-empty-text {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
  }
  .full-screen {
    &-title {
      position: absolute;
      top: 0;
      left: 0;
    }
    &-close-button {
      position: absolute;
      top: 0;
      right: 0;
    }
  }
  .smart-widget-grid-area {
    position: relative;
    .vue-grid-layout {
      position: absolute;
      width: 100%;
      transform: translateY(-8px);
      .smartwidget {
        box-shadow: none !important;
      }
    }
  }
  @keyframes blink {
    0%, 100% {
      opacity: 0.3;
    }
    50% {
      opacity: 1;
    }
  }
  @keyframes pulse {
    0%, 100% {
      transform: scale(1);
    }
    50% {
      transform: scale(1.2);
    }
  }
}
#top-layer {
  pointer-events: none;
  div {
    pointer-events: none;
  }
}
</style>